macro.command:
if(args[0].macroPass === "preDamageRollComplete") {
  if(workflow.hitTargets.size === 0) return;
  let target = workflow.hitTargets.first();

  const hasConcApplied = target.actor.appliedEffects.some(e => e.name.includes("Concentrating"));
	if (!hasConcApplied) return;

  let effectData = [{
    "origin": macroItem.uuid,
    "disabled": false,
    "name": `${macroItem.name} - Disadvantage`,
    "img": macroItem.img,
    "type": "base",
    "changes": [
      {
        "key": "flags.midi-qol.disadvantage.concentration",
        "mode": 0,
        "value": "1",
        "priority": 20
      }
    ],
    "transfer": false,
    "flags": {
      "dae": {
        "specialDuration": [
          "isSave.con"
        ]
      }
    }
  }];

  await MidiQOL.socket().executeAsGM("createEffects", { actorUuid: target.actor.uuid, effects: effectData });
}

